+/// Freeze header for full model state (128 bytes for extensibility)
+pub const FreezeHeader = extern struct {
+    magic: u32 = FREEZE_MAGIC,
+    version: u32 = FREEZE_VERSION,
+    model_hash: u64, // Hash of model architecture
+    model_path_len: u32, // Length of model path string
+    model_path_hash: u64, // Hash of original model file path
+    model_size: u64, // Size of serialized model data
+    context_size: u64, // Size of serialized context data (optional)
+    created_at: i64, // Unix timestamp
+    n_ctx: u32, // Context window size
+    n_batch: u32, // Batch size
+    n_gpu_layers: i32, // GPU layers offloaded
+    kv_type: u32, // KV cache quantization type
+    flags: u32 = 0, // Reserved flags
+    _pad: [52]u8 = [_]u8{0} ** 52, // Padding to 128 bytes
+};
+
+comptime {
+    if (@sizeOf(FreezeHeader) != 128) {
+        @compileError("FreezeHeader must be exactly 128 bytes");
+    }
+}
