 }

+test "freeze header size" {
+    try std.testing.expectEqual(@as(usize, 128), @sizeOf(FreezeHeader));
+}
+
 test "model hash deterministic" {
     // Hash should be deterministic for same model params
     const hash1: u64 = 0x1234 ^ (@as(u64, 768) << 16) ^ (@as(u64, 12) << 32);
     const hash2: u64 = 0x1234 ^ (@as(u64, 768) << 16) ^ (@as(u64, 12) << 32);
     try std.testing.expectEqual(hash1, hash2);
 }
+
+test "system prompt hash" {
+    const prompt1 = "You are a helpful assistant";
+    const prompt2 = "You are a helpful assistant";
+    const prompt3 = "You are a different assistant";
+
+    const hash1 = hashSystemPrompt(prompt1);
+    const hash2 = hashSystemPrompt(prompt2);
+    const hash3 = hashSystemPrompt(prompt3);
+
+    try std.testing.expectEqual(hash1, hash2);
+    try std.testing.expect(hash1 != hash3);
+}
